{

  int N, x;



  cin >> N >> x;





  int bottom = 2 * N - 1;

  deque< int > val;

  bool used[500001] = {};



  if(2 <= x && x + 2 <= bottom) {

    val.push_back(x + 1);

    used[x + 1] = true;

    val.push_back(x);

    used[x] = true;

    val.push_back(x - 1);

    used[x - 1] = true;

    val.push_back(x + 2);

    used[x + 2] = true;





  } else if(1 <= x - 2 && x + 1 <= bottom) {

    val.push_back(x - 1);

    used[x - 1] = true;

    val.push_back(x);

    used[x] = true;

    val.push_back(x + 1);

    used[x + 1] = true;

    val.push_back(x - 2);

    used[x - 2] = true;

  }





  if(val.empty()) {

    if(N == 2 && x == 2) {

      cout << "Yes" << endl;

      cout << "1" << endl;

      cout << "2" << endl;

      cout << "3" << endl;

    } else {

      cout << "No" << endl;

    }

